BEGIN;
INSERT INTO public.procedures (id, specialty, titles, synonyms, content, is_pro)
VALUES ('chirurgie_pied_cheville', 'orthopedie', '{"fr": "Chirurgie du pied et de la cheville (hallux valgus / ostéotomie)", "en": "Foot and ankle surgery (hallux valgus / osteotomy)", "pt": "Cirurgia do pé e tornozelo (hallux valgus / osteotomia)"}'::jsonb, '{"fr": ["hallux valgus", "ostéotomie métatarse", "arthrodèse cheville", "chirurgie avant-pied", "Scarf", "Chevron"], "en": ["hallux valgus", "bunion surgery", "metatarsal osteotomy", "ankle arthrodesis"], "pt": ["hallux valgus", "cirurgia do pé", "osteotomia metatarso"]}'::jsonb, '{"quick": {"fr": {"preop": ["Evaluation vasculaire périphérique (pouls pédieux + tibial postérieur) — diabète fréquemment associé", "Bilan glycémique si diabète : objectif HbA1c < 8% pour chirurgie électivie", "Bloc poplité (nerf sciatique) + bloc saphène = analgésie complète du pied et de la cheville", "Bloc de cheville (ankle block) 5 nerfs pour chirurgie avant-pied isolée", "Chirurgie souvent ambulatoire — informer patient sur retour à domicile avec bloc en place"], "intraop": ["ALR préférentielle : bloc poplité (sciatique) + saphène sous garrot (1h30 toléré sous ALR)", "Garrot pneumatique à la cheville (250-350 mmHg) ou cuisse (300-400 mmHg)", "Si AG : propofol + masque laryngé (LMA) acceptable (chirurgie non-algique sous bloc)", "Position décubitus dorsal, pied déclive sur sac — préserver accès rachis si rachianesthésie", "Rachianesthésie (bupivacaine hyperbare 7.5-10 mg) alternative si bloc difficile ou patient préfère", "Antibioprophylaxie : cefazoline 2g IV avant garrot"], "postop": ["Analgésie prolongée (bloc poplité continu 24-48h si disponible) : excellente tolérance ambulatoire", "Relais oral : paracetamol + AINS + codéine si besoin", "Décharge ou appui talon selon technique — informer patient avant sortie", "Chaussure de décharge post-chirurgicale obligatoire", "HBPM 7-10 jours (garrot + immobilisation partielle)"], "red_flags": ["Ischémie cutanée (garrot prolongé > 2h ou garrot cheville > pression recommandée) — retrait garrot immédiat", "Infection plaie (diabétique ++) : revoir J5-J7 — urgence si fièvre + érythème + pus", "Syndrome douloureux régional complexe (SDRC type I) : douleurs disproportionnées + allodynie J7-J30 — kinési + traitement précoce", "Thrombose veineuse profonde distale (garrot + immobilisation) — HBPM systématique"], "drugs": [{"drug_id": "propofol", "indication_tag": "induction_ou_sedation"}, {"drug_id": "bupivacaine", "indication_tag": "bloc_poplite"}, {"drug_id": "paracetamol", "indication_tag": "analgesie"}, {"drug_id": "ketorolac", "indication_tag": "analgesie"}, {"drug_id": "ondansetron", "indication_tag": "PONV"}, {"drug_id": "cefazoline", "indication_tag": "antibioprophylaxie"}, {"drug_id": "enoxaparine", "indication_tag": "thromboprophylaxie"}]}}, "deep": {"fr": {"clinical": ["Le bloc poplité (nerf sciatique poplité) + bloc du nerf saphène couvre la totalité du pied et de la cheville — gold standard pour cette chirurgie.", "La chirurgie du pied est idéale pour l''ambulatoire si ALR : patient rentre avec bloc actif, antalgiques oraux pour relais.", "Le garrot à la cheville est mieux toléré que le garrot de cuisse (moins douloureux) mais doit respecter des pressions inférieures.", "Le diabète augmente le risque infectieux et retarde la cicatrisation — surveillance rapprochée J5-J7."], "pitfalls": ["Garrot à la cheville contre-indiqué si artériopathie périphérique sévère (IPS < 0.5).", "Le bloc de cheville (5 nerfs) ne suffit pas pour une chirurgie de la cheville ou du médio-pied — bloc poplité nécessaire.", "Informer le patient que le pied sera insensible et chaud 12-18h après le bloc — risque de brûlure involontaire (bouillotte, bain chaud)."], "references": [{"source": "ASRA — Lower Extremity Peripheral Nerve Blocks", "year": 2021, "note": "Popliteal and ankle block techniques"}, {"source": "SFAR — Anesthésie ambulatoire", "year": 2021, "note": "Protocoles chirurgie ambulatoire du pied"}, {"source": "AOFAS — Foot and Ankle Surgery Guidelines", "year": 2022, "note": "Recommendations perioperative care"}]}}}'::jsonb, false)
ON CONFLICT (id) DO UPDATE SET specialty=EXCLUDED.specialty, titles=EXCLUDED.titles, synonyms=EXCLUDED.synonyms, content=EXCLUDED.content, updated_at=now();
INSERT INTO public.procedures (id, specialty, titles, synonyms, content, is_pro)
VALUES ('amputation_membre', 'orthopedie', '{"fr": "Amputation de membre (vasculaire / traumatique)", "en": "Limb amputation (vascular / traumatic)", "pt": "Amputação de membro (vascular / traumática)"}'::jsonb, '{"fr": ["amputation jambe", "amputation cuisse", "amputation transtibiale", "amputation transfémorale", "désarticulation genou"], "en": ["BKA", "AKA", "below-knee amputation", "above-knee amputation", "limb amputation"], "pt": ["amputação membro", "amputação transtibial", "amputação transfemoral"]}'::jsonb, '{"quick": {"fr": {"preop": ["Bilan vasculaire complet : TCPO2, écho-doppler artériel, bilan biologique (albumine, NFS)", "Optimisation comorbidités : diabète (glycémie < 10 mmol/L perop), insuffisance rénale, cardiopathie", "Discuter cathéter périnerveux préopératoire (fémoral ou sciatique) pour prévention douleur fantôme", "Information patient : douleurs fantômes (70-80% des amputés), rééducation appareillage", "Consentement niveau d''amputation : décision finale peropératoire selon vitalité tissulaire"], "intraop": ["AG ou rachianesthésie (niveau T10) ou ALR (bloc fémoral + sciatique) selon niveau d''amputation", "Rachianesthésie préférée pour amputation transtibiale : excellente qualité, prévention douleur fantôme", "Si AG : propofol + sufentanil, éviter halogéné si cardiopathie sévère", "Garrot pneumatique (sauf si amputation ischémique = garrot CI)", "Antibioprophylaxie : cefazoline 2g IV (+ métronidazole si gangrène gazeuse ou contamination fécale)", "Prélèvement bactériologique per-opératoire si plaie infectée"], "postop": ["Cathéter périnerveux continu (fémoral ou sciatique) 5-7 jours : prévention douleur fantôme (niveau de preuve modéré)", "Gabapentine ou prégabaline dès J0 : réduction incidence douleur fantôme (NICE recommandé)", "Miroir thérapeutique dès J2-J3 : réduction douleur fantôme", "Surveillance moignon : saignement, ischémie distale, infection", "HBPM prophylaxie pendant 30 jours (immobilisation + terrain vasculaire)"], "red_flags": ["Douleurs fantômes intenses précoces (J0-J3) : ajuster analgésie — gabapentine + amitriptyline", "Ischémie moignon postopératoire : révision niveau d''amputation", "Sepsis sur moignon infecté (gangrène progressante) : reprise chirurgicale urgente", "Embolie pulmonaire (terrain vasculaire + immobilisation) : mobilisation précoce + HBPM"], "drugs": [{"drug_id": "propofol", "indication_tag": "induction"}, {"drug_id": "rocuronium", "indication_tag": "intubation"}, {"drug_id": "sugammadex", "indication_tag": "reversal"}, {"drug_id": "sufentanil", "indication_tag": "analgesie_perop"}, {"drug_id": "bupivacaine", "indication_tag": "catheter_perinerveux"}, {"drug_id": "ketamine", "indication_tag": "prevention_douleur_fantome"}, {"drug_id": "paracetamol", "indication_tag": "analgesie"}, {"drug_id": "morphine", "indication_tag": "analgesie_postop"}, {"drug_id": "cefazoline", "indication_tag": "antibioprophylaxie"}]}}, "deep": {"fr": {"clinical": ["Les douleurs fantômes affectent 70-80% des amputés — leur prévention commence en peropératoire (rachianesthésie, cathéter périnerveux, kétamine).", "La rachianesthésie pour amputation transtibiale est supérieure à l''AG pour la prévention des douleurs fantômes (niveau de preuve II).", "L''état nutritionnel (albumine < 30 g/L) est un facteur de risque de retard de cicatrisation — corriger si possible avant chirurgie élective.", "Le niveau d''amputation est parfois décidé peropératoire (vitalité tissulaire, saignement osseux) — informer le patient."], "pitfalls": ["Garrot contre-indiqué en cas d''amputation pour ischémie — le saignement est le seul indicateur de vitalité tissulaire.", "Ne pas administrer de vasoconstricteurs locaux (adrénaline) dans les zones ischémiques.", "La gabapentine doit être démarrée AVANT la chirurgie pour réduction maximale de la douleur fantôme."], "references": [{"source": "Cochrane Review — Phantom limb pain prevention", "year": 2021, "note": "Regional anesthesia and phantom pain"}, {"source": "SFAR — Amputations vasculaires", "year": 2020, "note": "Protocole anesthésie amputation"}, {"source": "NICE — Peripheral arterial disease", "year": 2022, "note": "Perioperative management"}]}}}'::jsonb, false)
ON CONFLICT (id) DO UPDATE SET specialty=EXCLUDED.specialty, titles=EXCLUDED.titles, synonyms=EXCLUDED.synonyms, content=EXCLUDED.content, updated_at=now();
INSERT INTO public.procedures (id, specialty, titles, synonyms, content, is_pro)
VALUES ('fracture_humerus_proximal', 'orthopedie', '{"fr": "Fracture de l''humérus proximal (ORIF / prothèse)", "en": "Proximal humerus fracture (ORIF / arthroplasty)", "pt": "Fratura do úmero proximal (ORIF / artroplastia)"}'::jsonb, '{"fr": ["fracture humérus proximal", "fracture col humérus", "fracture épaule", "ORIF humérus", "prothèse humérale"], "en": ["proximal humerus fracture", "humeral fracture", "shoulder fracture", "ORIF humerus"], "pt": ["fratura úmero proximal", "fratura do ombro"]}'::jsonb, '{"quick": {"fr": {"preop": ["Patient souvent âgé + ostéoporose : évaluer fragilité (score CFS), état cognitif, comorbidités", "Imagerie : radiographies F+P+Y-view + scanner 3D si fracture comminutive pour planification chirurgicale", "Décision ORIF vs prothèse humérale (hémiartroplastie ou PTI) selon fragments et âge", "Bloc interscalène préopératoire pour antalgie dès les urgences", "Position décubitus dorsal ou beach chair selon chirurgien — évaluer PA radiale avant installation"], "intraop": ["Position beach chair (30-45°) ou decubitus dorsal avec billot sous l''épaule", "PA invasive (artère radiale) systématique si beach chair : maintenir PAM > 70 mmHg cérébral", "AG + IOT + bloc interscalène ou ALR seul + sédation légère", "TIVA (propofol + remifentanil) recommandée en beach chair pour reveil rapide", "Fluoroscopie peropératoire : protéger équipe (thyroïde, tablier plombé)", "Antibioprophylaxie : cefazoline 2g IV avant incision", "Durée opératoire variable (1-3h selon technique) : prévoir réchauffement actif"], "postop": ["Immobilisation coude au corps 4-6 semaines — écharpe + attelle", "Analgésie : bloc interscalène continu 48h (ropivacaine 0.2% 5-8 mL/h) + paracetamol + AINS", "Sans bloc continu : paracetamol + AINS + morphine PO titrée", "Thromboprophylaxie : HBPM 14-28 jours selon mobilité", "Kinésithérapie immédiate (J1-J2) en pendulaire doux si fracture stable"], "red_flags": ["Hypotension peropératoire en beach chair (PAM < 60 cérébral) : noradrenaline prete, repositionner si persiste", "Lésion vasculaire axillaire (rare, fractures avec luxation) : angioscanner urgent", "Paralysie nerveuse postopératoire (nerf axillaire ++) : EMG J21 si pas de récupération", "Nécrose tête humérale (ORIF fragments déplacés) : révision prothétique à 1-2 ans"], "drugs": [{"drug_id": "propofol", "indication_tag": "induction"}, {"drug_id": "rocuronium", "indication_tag": "intubation"}, {"drug_id": "sugammadex", "indication_tag": "reversal"}, {"drug_id": "remifentanil", "indication_tag": "analgesie_TIVA"}, {"drug_id": "noradrenaline", "indication_tag": "PAM_beach_chair"}, {"drug_id": "bupivacaine", "indication_tag": "bloc_interscalene"}, {"drug_id": "paracetamol", "indication_tag": "analgesie"}, {"drug_id": "ketorolac", "indication_tag": "analgesie"}, {"drug_id": "ondansetron", "indication_tag": "PONV"}, {"drug_id": "dexamethasone", "indication_tag": "PONV"}, {"drug_id": "cefazoline", "indication_tag": "antibioprophylaxie"}]}}, "deep": {"fr": {"clinical": ["La fracture de l''humérus proximal est la 3e fracture la plus fréquente chez le sujet âgé (après poignet et hanche).", "Le bloc interscalène est le gold standard pour l''analgésie peropératoire et postopératoire — réduction morphine de 60-70%.", "La décision ORIF vs prothèse est critique : fractures à 4 fragments (classification Neer) → prothèse (meilleurs résultats fonctionnels).", "En beach chair, la PAM mesurée au poignet doit être augmentée de ~15 mmHg pour estimer la pression cérébrale réelle."], "pitfalls": ["Bloc interscalène : toujours vérifier l''absence de pneumopathie controlatérale avant réalisation (paralysie phrénique).", "L''ostéoporose sévère peut rendre l''ostéosynthèse impossible — discuter prothèse emblée si T-score < -3.", "Fracture-luxation : risque de lésion vasculaire axillaire — palper le pouls avant et après réduction."], "references": [{"source": "SOFCOT — Fractures humérus proximal", "year": 2022, "note": "Classification et traitement"}, {"source": "ASRA — Interscalene block", "year": 2021, "note": "Regional anesthesia shoulder"}, {"source": "Cochrane — ORIF vs arthroplasty proximal humerus", "year": 2021, "note": "Comparative outcomes elderly"}]}}}'::jsonb, false)
ON CONFLICT (id) DO UPDATE SET specialty=EXCLUDED.specialty, titles=EXCLUDED.titles, synonyms=EXCLUDED.synonyms, content=EXCLUDED.content, updated_at=now();
COMMIT;

